1	// Example form component demonstrating Prisma + Zod integration
2	// This shows how to use the new typed validation in React components
3	
4	import React, { useState } from "react";
5	import { Button } from "@/shared/components/ui/button";
6	import { Input } from "@/shared/components/ui/input";
7	import { Label } from "@/shared/components/ui/label";
8	import { Textarea } from "@/shared/components/ui/textarea";
9	import { Badge } from "@/shared/components/ui/badge";
10	import { Card, CardContent, CardHeader, CardTitle } from "@/shared/components/ui/card";
11	import { Alert, AlertDescription } from "@/shared/components/ui/alert";
12	import { X, Plus } from "lucide-react";
13	
14	import { useProjectForm } from "@/shared/hooks/useTypedValidation";
15	import { createProject } from "@/lib/services/typed-projects";
16	import type { Project } from "@/lib/services/typed-operations";
17	
18	interface TypedProjectFormProps {
19	  onSuccess?: (project: Project) => void;
20	  onCancel?: () => void;
21	  initialData?: Partial<{
22	    name: string;
23	    description: string;
24	    tags: string[];
25	  }>;
26	}
27	
28	export default function TypedProjectForm({
29	  onSuccess,
30	  onCancel,
31	  initialData,
32	}: TypedProjectFormProps) {
33	  const { formData, updateField, handleSubmit, validation, isValid } =
34	    useProjectForm();
35	  const [isSubmitting, setIsSubmitting] = useState(false);
36	  const [submitError, setSubmitError] = useState<string>();
37	  const [newTag, setNewTag] = useState("");
38	
39	  // Initialize form with provided data
40	  React.useEffect(() => {
41	    if (initialData) {
42	      Object.entries(initialData).forEach(([key, value]) => {
43	        if (value !== undefined) {
44	          updateField(key, value);
45	        }
46	      });
47	    }
48	  }, [initialData, updateField]);
49	
50	  const handleAddTag = () => {
51	    if (newTag.trim() && !formData.tags.includes(newTag.trim())) {
52	      updateField("tags", [...formData.tags, newTag.trim()]);
53	      setNewTag("");
54	    }
55	  };
56	
57	  const handleRemoveTag = (tagToRemove: string) => {
58	    updateField(
59	      "tags",
60	      formData.tags.filter((tag) => tag !== tagToRemove)
61	    );
62	  };
63	
64	  const handleFormSubmit = async (e: React.FormEvent) => {
65	    e.preventDefault();
66	    setIsSubmitting(true);
67	    setSubmitError(undefined);
68	
69	    try {
70	      const result = await handleSubmit(async (validatedData) => {
71	        // Use our typed service to create the project
72	        const createResult = await createProject(validatedData);
73	
74	        if (!createResult.success) {
75	          throw new Error(
76	            createResult.errors?.join(", ") || "Failed to create project"
77	          );
78	        }
79	
80	        if (createResult.project && onSuccess) {
81	          onSuccess(createResult.project);
82	        }
83	      });
84	
85	      if (!result.success) {
86	        setSubmitError(result.error || "Validation failed");
87	      }
88	    } catch (error) {
89	      setSubmitError(
90	        error instanceof Error ? error.message : "Unknown error occurred"
91	      );
92	    } finally {
93	      setIsSubmitting(false);
94	    }
95	  };
96	
97	  return (
98	    <Card className="w-full max-w-2xl mx-auto">
99	      <CardHeader>
100	        <CardTitle>Create New Project</CardTitle>
101	      </CardHeader>
102	      <CardContent>
103	        <form onSubmit={handleFormSubmit} className="space-y-6">
104	          {/* Project Name */}
105	          <div className="space-y-2">
106	            <Label htmlFor="name">Project Name *</Label>
107	            <Input
108	              id="name"
109	              value={formData.name}
110	              onChange={(e) => updateField("name", e.target.value)}
111	              onBlur={() => validation.validateField("name", formData.name)}
112	              placeholder="Enter project name"
113	              className={
114	                validation.hasFieldError("name") ? "border-red-500" : ""
115	              }
116	            />
117	            {validation.hasFieldError("name") && (
118	              <p className="text-sm text-red-500">
119	                {validation.getFieldError("name")}
120	              </p>
121	            )}
122	          </div>
123	
124	          {/* Project Description */}
125	          <div className="space-y-2">
126	            <Label htmlFor="description">Description</Label>
127	            <Textarea
128	              id="description"
129	              value={formData.description}
130	              onChange={(e) => updateField("description", e.target.value)}
131	              onBlur={() =>
132	                validation.validateField("description", formData.description)
133	              }
134	              placeholder="Describe your project"
135	              rows={3}
136	              className={
137	                validation.hasFieldError("description") ? "border-red-500" : ""
138	              }
139	            />
140	            {validation.hasFieldError("description") && (
141	              <p className="text-sm text-red-500">
142	                {validation.getFieldError("description")}
143	              </p>
144	            )}
145	          </div>
146	
147	          {/* Tags */}
148	          <div className="space-y-2">
149	            <Label>Tags</Label>
150	            <div className="flex flex-wrap gap-2 mb-2">
151	              {formData.tags.map((tag) => (
152	                <Badge
153	                  key={tag}
154	                  variant="secondary"
155	                  className="flex items-center gap-1"
156	                >
157	                  {tag}
158	                  <button
159	                    type="button"
160	                    onClick={() => handleRemoveTag(tag)}
161	                    className="ml-1 hover:text-red-500"
162	                  >
163	                    <X className="h-3 w-3" />
164	                  </button>
165	                </Badge>
166	              ))}
167	            </div>
168	            <div className="flex gap-2">
169	              <Input
170	                value={newTag}
171	                onChange={(e) => setNewTag(e.target.value)}
172	                onKeyDown={(e) =>
173	                  e.key === "Enter" && (e.preventDefault(), handleAddTag())
174	                }
175	                placeholder="Add a tag"
176	                className="flex-1"
177	              />
178	              <Button
179	                type="button"
180	                onClick={handleAddTag}
181	                variant="outline"
182	                size="sm"
183	                disabled={!newTag.trim()}
184	              >
185	                <Plus className="h-4 w-4" />
186	              </Button>
187	            </div>
188	          </div>
189	
190	          {/* Validation Summary */}
