1	// XState machine for managing dual-environment canvas (Practical/Design)
2	// This manages the complex state transitions between React Flow and Excalidraw environments
3	
4	import { createMachine, assign } from "xstate";
5	
6	// Canvas environment types
7	export type CanvasEnvironment = "practical" | "design";
8	export type NavigationTool = "move" | "hand" | "scale";
9	export type PracticalTool = "select" | "connect" | "pan" | "zoom";
10	export type DesignTool =
11	  | "hand"
12	  | "selection"
13	  | "rectangle"
14	  | "diamond"
15	  | "ellipse"
16	  | "arrow"
17	  | "line"
18	  | "freedraw"
19	  | "text"
20	  | "image"
21	  | "eraser";
22	
23	// Canvas context interface
24	export interface CanvasContext {
25	  currentEnvironment: CanvasEnvironment;
26	  navigationTool: NavigationTool;
27	  practicalTool: PracticalTool;
28	  designTool: DesignTool;
29	
30	  // Environment-specific states
31	  isWhiteboardActive: boolean;
32	  isPassthroughMode: boolean; // For space-bar panning in design mode
33	  keepToolActive: boolean;
34	
35	  // Drawing preferences
36	  strokeColor?: string;
37	  strokeWidth?: number;
38	
39	  // Viewport synchronization
40	  viewport: {
41	    x: number;
42	    y: number;
43	    zoom: number;
44	  };
45	
46	  // Collaboration state
47	  isCollaborationActive: boolean;
48	  collaborators: Array<{
49	    id: string;
50	    cursor?: { x: number; y: number };
51	    environment: CanvasEnvironment;
52	  }>;
53	
54	  // Canvas data
55	  practicalNodes: any[];
56	  practicalEdges: any[];
57	  designElements: any[];
58	  designAppState: any;
59	
60	  // Error state
61	  error?: string;
62	}
63	
64	// Events that can be sent to the machine
65	export type CanvasEvent =
66	  | { type: "SWITCH_TO_PRACTICAL" }
67	  | { type: "SWITCH_TO_DESIGN" }
68	  | { type: "SET_NAVIGATION_TOOL"; tool: NavigationTool }
69	  | { type: "SET_PRACTICAL_TOOL"; tool: PracticalTool }
70	  | { type: "SET_DESIGN_TOOL"; tool: DesignTool }
71	  | { type: "ENABLE_PASSTHROUGH" }
72	  | { type: "DISABLE_PASSTHROUGH" }
73	  | { type: "TOGGLE_KEEP_TOOL_ACTIVE" }
74	  | { type: "SET_STROKE_COLOR"; color: string }
75	  | { type: "SET_STROKE_WIDTH"; width: number }
76	  | {
77	      type: "UPDATE_VIEWPORT";
78	      viewport: { x: number; y: number; zoom: number };
79	    }
80	  | {
81	      type: "ADD_COLLABORATOR";
82	      collaborator: { id: string; environment: CanvasEnvironment };
83	    }
84	  | { type: "REMOVE_COLLABORATOR"; collaboratorId: string }
85	  | { type: "UPDATE_PRACTICAL_DATA"; nodes: any[]; edges: any[] }
86	  | { type: "UPDATE_DESIGN_DATA"; elements: any[]; appState: any }
87	  | { type: "SYNCHRONIZE_ENVIRONMENTS" }
88	  | { type: "RESET_CANVAS" }
89	  | { type: "ERROR"; error: string }
90	  | { type: "CLEAR_ERROR" };
91	
92	// Initial context
93	const initialContext: CanvasContext = {
94	  currentEnvironment: "practical",
95	  navigationTool: "move",
96	  practicalTool: "select",
97	  designTool: "selection",
98	  isWhiteboardActive: false,
99	  isPassthroughMode: false,
100	  keepToolActive: false,
101	  viewport: { x: 0, y: 0, zoom: 1 },
102	  isCollaborationActive: false,
103	  collaborators: [],
104	  practicalNodes: [],
105	  practicalEdges: [],
106	  designElements: [],
107	  designAppState: {},
